'use client'

import React, { useState } from 'react';
import { useBudget } from '@/context/BudgetContext';
import { User, Lock, ArrowRight, Loader2, ShieldCheck, Wallet, AlertTriangle, Eye, EyeOff } from 'lucide-react';
import { GoogleLogin } from '@react-oauth/google';
import { useRouter } from 'next/navigation';

const FEATURES = [
    { icon: '🔒', title: 'ปลอดภัย 100%', desc: 'Enterprise-grade security' },
    { icon: '⚡', title: 'Real-time Data', desc: 'อัปเดตข้อมูลทันที' },
    { icon: '📊', title: 'Smart Analytics', desc: 'วิเคราะห์งบได้ทุกมิติ' },
]

export default function Login() {
    const { login, loginWithGoogle } = useBudget();
    const router = useRouter();
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [showPass, setShowPass] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');
    const [focusedField, setFocusedField] = useState<string | null>(null);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError('');
        try {
            const success = await login(username, password);
            if (success) {
                router.push('/dashboard');
            } else {
                setError('ชื่อผู้ใช้งานหรือรหัสผ่านไม่ถูกต้อง');
            }
        } catch (err: any) {
            setError(`เกิดข้อผิดพลาด: ${err.message || 'กรุณาลองใหม่อีกครั้ง'}`);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen w-full flex bg-white overflow-hidden">

            {/* ══════════════════════════════════════
                LEFT — IMMERSIVE BRAND EXPERIENCE
                ══════════════════════════════════════ */}
            <div className="hidden lg:flex lg:w-[52%] xl:w-[56%] flex-col relative overflow-hidden"
                style={{ background: 'linear-gradient(145deg, #003E6B 0%, #005A8E 35%, #0081AE 70%, #009FD4 100%)' }}>

                {/* Ambient Orbs */}
                <div className="absolute top-[-20%] right-[-15%] w-[600px] h-[600px] rounded-full opacity-20"
                    style={{ background: 'radial-gradient(circle, #00C8FF 0%, transparent 70%)' }} />
                <div className="absolute bottom-[-15%] left-[-10%] w-[500px] h-[500px] rounded-full opacity-15"
                    style={{ background: 'radial-gradient(circle, #0099CC 0%, transparent 70%)' }} />

                {/* Dot-grid texture */}
                <div className="absolute inset-0 opacity-[0.06]"
                    style={{ backgroundImage: 'radial-gradient(circle, rgba(255,255,255,0.8) 1px, transparent 1px)', backgroundSize: '28px 28px' }} />

                {/* Abstract wave shapes */}
                <svg className="absolute bottom-0 left-0 w-full opacity-5" viewBox="0 0 800 200" preserveAspectRatio="none">
                    <path d="M0,100 C200,0 400,200 600,100 L800,100 L800,200 L0,200 Z" fill="white" />
                </svg>

                {/* Content */}
                <div className="relative z-10 flex flex-col h-full px-14 py-12">

                    {/* Badge */}
                    <div className="inline-flex items-center gap-2 self-start px-4 py-2 rounded-full
                        bg-white/10 border border-white/15 backdrop-blur-sm">
                        <span className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse" />
                        <span className="text-[11px] font-bold text-white/80 tracking-[0.15em] uppercase">
                            ระบบบริหารงบประมาณองค์กร
                        </span>
                    </div>

                    {/* Main Hero */}
                    <div className="flex-1 flex flex-col justify-center space-y-10 max-w-lg">

                        {/* Logo + Title */}
                        <div className="space-y-6">
                            <div className="p-5 w-20 h-20 rounded-[28px] inline-flex items-center justify-center
                                bg-white/10 border border-white/20 backdrop-blur-md
                                shadow-[0_20px_60px_rgba(0,0,0,0.2)]
                                animate-float">
                                <Wallet className="w-10 h-10 text-white" strokeWidth={1.5} />
                            </div>

                            <div className="space-y-3">
                                <h1 className="text-[52px] font-black text-white tracking-[-0.03em] leading-none">
                                    SMART<br />
                                    <span className="text-transparent bg-clip-text select-none"
                                        style={{ WebkitTextStroke: '2px rgba(255,255,255,0.3)' }}>
                                        BUDGET
                                    </span>
                                </h1>
                                <p className="text-[16px] text-white/65 font-medium leading-relaxed max-w-xs">
                                    ยกระดับการบริหารงบประมาณด้วยความโปร่งใส แม่นยำ และรวดเร็ว
                                </p>
                            </div>
                        </div>

                        {/* Feature Pills */}
                        <div className="space-y-3">
                            {FEATURES.map((f, i) => (
                                <div key={i}
                                    className="flex items-center gap-4 p-4 rounded-2xl
                                        bg-white/8 border border-white/10 backdrop-blur-sm
                                        hover:bg-white/12 transition-colors duration-200 group"
                                    style={{ animationDelay: `${i * 100}ms` }}>
                                    <div className="w-10 h-10 flex items-center justify-center rounded-xl bg-white/10 text-xl flex-shrink-0">
                                        {f.icon}
                                    </div>
                                    <div>
                                        <p className="text-[13px] font-bold text-white">{f.title}</p>
                                        <p className="text-[11px] text-white/55 font-medium">{f.desc}</p>
                                    </div>
                                    <div className="ml-auto w-5 h-5 rounded-full bg-white/10 flex items-center justify-center
                                        group-hover:bg-white/20 transition-colors">
                                        <ArrowRight className="w-3 h-3 text-white/60" />
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Footer */}
                    <div className="flex items-center justify-between">
                        <p className="text-[10px] font-bold text-white/25 tracking-[0.2em] uppercase">
                            Secured by DCC Platform • v3.0
                        </p>
                        <div className="flex gap-1.5">
                            <div className="w-6 h-1.5 rounded-full bg-white" />
                            <div className="w-2 h-1.5 rounded-full bg-white/30" />
                            <div className="w-2 h-1.5 rounded-full bg-white/30" />
                        </div>
                    </div>
                </div>
            </div>

            {/* ══════════════════════════════════════
                RIGHT — PREMIUM LOGIN FORM
                ══════════════════════════════════════ */}
            <div className="flex-1 flex flex-col items-center justify-center px-8 py-10 relative overflow-hidden
                bg-gradient-to-br from-[#F6FBFF] via-white to-white">

                {/* Subtle background decoration */}
                <div className="absolute top-0 right-0 w-64 h-64 rounded-full opacity-40 -translate-y-1/2 translate-x-1/2"
                    style={{ background: 'radial-gradient(circle, #E0F4FD 0%, transparent 70%)' }} />
                <div className="absolute bottom-0 left-0 w-48 h-48 rounded-full opacity-30 translate-y-1/2 -translate-x-1/2"
                    style={{ background: 'radial-gradient(circle, #E0F4FD 0%, transparent 70%)' }} />

                <div className="w-full max-w-[384px] relative z-10 animate-in fade-in slide-in-from-bottom-4 duration-700">

                    {/* ── Header ── */}
                    <div className="mb-9 space-y-2">
                        {/* Mobile logo */}
                        <div className="lg:hidden w-12 h-12 rounded-2xl bg-gradient-to-br from-primary-500 to-primary-700
                            flex items-center justify-center mb-5
                            shadow-[0_8px_24px_rgba(0,159,212,0.30)]">
                            <Wallet className="w-6 h-6 text-white" strokeWidth={2} />
                        </div>

                        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary-50 border border-primary-100 mb-3">
                            <ShieldCheck className="w-3 h-3 text-primary-600" strokeWidth={2.5} />
                            <span className="text-[10px] font-extrabold text-primary-600 uppercase tracking-[0.15em]">Secure Login</span>
                        </div>
                        <h2 className="text-[32px] font-black text-gray-900 tracking-tight leading-tight">
                            ยินดีต้อนรับ<br />กลับมา 👋
                        </h2>
                        <p className="text-[14px] text-gray-400 font-medium">
                            เข้าสู่ระบบเพื่อบริหารงบประมาณ DCC
                        </p>
                    </div>

                    {/* ── Error State ── */}
                    {error && (
                        <div className="mb-5 flex items-start gap-3 p-4 bg-red-50 border border-red-100 rounded-[18px]
                            animate-in slide-in-from-top-2 duration-300">
                            <div className="w-8 h-8 rounded-xl bg-red-100 flex items-center justify-center flex-shrink-0">
                                <AlertTriangle className="w-4 h-4 text-red-600" strokeWidth={2.5} />
                            </div>
                            <div>
                                <p className="text-[13px] font-bold text-red-700 leading-tight">เกิดข้อผิดพลาด</p>
                                <p className="text-[12px] text-red-500 font-medium mt-0.5">{error}</p>
                            </div>
                        </div>
                    )}

                    {/* ── Form ── */}
                    <form onSubmit={handleSubmit} className="space-y-4">
                        {/* Username Field */}
                        <div className="space-y-1.5">
                            <label className="text-[11px] font-extrabold text-gray-400 uppercase tracking-[0.18em] px-1">
                                ชื่อผู้ใช้งาน
                            </label>
                            <div className={`relative rounded-[18px] transition-all duration-200
                                ${focusedField === 'user' ? 'ring-2 ring-primary-400/30' : ''}`}>
                                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                    <User className={`w-[18px] h-[18px] transition-colors duration-200
                                        ${focusedField === 'user' ? 'text-primary-500' : 'text-gray-300'}`}
                                        strokeWidth={2} />
                                </div>
                                <input
                                    type="text"
                                    required
                                    value={username}
                                    onChange={(e) => setUsername(e.target.value)}
                                    onFocus={() => setFocusedField('user')}
                                    onBlur={() => setFocusedField(null)}
                                    className="w-full pl-11 pr-4 py-[14px] rounded-[18px]
                                        bg-gray-50/80 border-2 border-transparent font-semibold text-gray-900 text-[14px]
                                        placeholder:text-gray-300 placeholder:font-normal
                                        focus:border-primary-400 focus:bg-white focus:outline-none
                                        focus:shadow-[0_0_0_4px_rgba(0,159,212,0.08),0_4px_24px_rgba(0,159,212,0.12)]
                                        transition-all duration-200 disabled:opacity-50"
                                    placeholder="กรอกชื่อผู้ใช้งาน"
                                    disabled={isLoading}
                                    autoComplete="username"
                                />
                            </div>
                        </div>

                        {/* Password Field */}
                        <div className="space-y-1.5">
                            <label className="text-[11px] font-extrabold text-gray-400 uppercase tracking-[0.18em] px-1">
                                รหัสผ่าน
                            </label>
                            <div className={`relative rounded-[18px] transition-all duration-200
                                ${focusedField === 'pass' ? 'ring-2 ring-primary-400/30' : ''}`}>
                                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                    <Lock className={`w-[18px] h-[18px] transition-colors duration-200
                                        ${focusedField === 'pass' ? 'text-primary-500' : 'text-gray-300'}`}
                                        strokeWidth={2} />
                                </div>
                                <input
                                    type={showPass ? 'text' : 'password'}
                                    required
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    onFocus={() => setFocusedField('pass')}
                                    onBlur={() => setFocusedField(null)}
                                    className="w-full pl-11 pr-12 py-[14px] rounded-[18px]
                                        bg-gray-50/80 border-2 border-transparent font-semibold text-gray-900 text-[14px]
                                        placeholder:text-gray-300 placeholder:font-normal placeholder:tracking-normal
                                        focus:border-primary-400 focus:bg-white focus:outline-none
                                        focus:shadow-[0_0_0_4px_rgba(0,159,212,0.08),0_4px_24px_rgba(0,159,212,0.12)]
                                        transition-all duration-200 disabled:opacity-50"
                                    placeholder="••••••••"
                                    disabled={isLoading}
                                    autoComplete="current-password"
                                />
                                <button type="button" onClick={() => setShowPass(!showPass)}
                                    className="absolute inset-y-0 right-0 pr-4 flex items-center text-gray-300 hover:text-gray-500 transition-colors">
                                    {showPass
                                        ? <EyeOff className="w-4 h-4" strokeWidth={2} />
                                        : <Eye className="w-4 h-4" strokeWidth={2} />
                                    }
                                </button>
                            </div>
                        </div>

                        {/* Submit Button */}
                        <div className="pt-2">
                            <button type="submit" disabled={isLoading}
                                className="btn-primary w-full h-[54px] rounded-[18px] text-[15px] font-extrabold
                                    disabled:opacity-50 disabled:cursor-not-allowed disabled:pointer-events-none
                                    active:scale-[0.98] transition-transform">
                                {isLoading ? (
                                    <Loader2 className="w-5 h-5 animate-spin" />
                                ) : (
                                    <span className="flex items-center gap-2">
                                        เข้าสู่ระบบ
                                        <ArrowRight className="w-5 h-5" strokeWidth={2.5} />
                                    </span>
                                )}
                            </button>
                        </div>
                    </form>

                    {/* ── Divider ── */}
                    <div className="flex items-center gap-4 my-5">
                        <div className="flex-1 h-px bg-gray-100" />
                        <span className="text-[10px] font-bold text-gray-300 uppercase tracking-[0.15em]">หรือ</span>
                        <div className="flex-1 h-px bg-gray-100" />
                    </div>

                    {/* ── Google Login ── */}
                    <div className="flex justify-center">
                        <GoogleLogin
                            onSuccess={async (credentialResponse) => {
                                if (credentialResponse.credential) {
                                    setIsLoading(true);
                                    try {
                                        const success = await loginWithGoogle(credentialResponse.credential);
                                        if (success) router.push('/dashboard');
                                    } catch { setError('Google Sign-In Error'); }
                                    finally { setIsLoading(false); }
                                }
                            }}
                            onError={() => setError('Google Sign-In Failed')}
                            shape="pill" theme="outline" size="large"
                        />
                    </div>

                    {/* ── Footer Trust Badge ── */}
                    <div className="mt-8 pt-6 border-t border-gray-50 flex items-center justify-between">
                        <div className="flex items-center gap-1.5">
                            <div className="w-4 h-4 rounded-full bg-emerald-500/10 flex items-center justify-center">
                                <div className="w-2 h-2 rounded-full bg-emerald-500" />
                            </div>
                            <span className="text-[10px] font-bold text-gray-300 uppercase tracking-[0.15em]">
                                Secure Connection
                            </span>
                        </div>
                        <span className="text-[10px] font-bold text-gray-300 tracking-[0.1em]">
                            © 2026 DCC Digital Trust
                        </span>
                    </div>
                </div>
            </div>
        </div>
    );
}
